using Microsoft.AspNetCore.HttpOverrides;
using System.Net;
using System.Net.Http;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// FIX 1 — Scoped-in-singleton: ValidateScopes (now on by default in dev)
// would throw at startup. Use a scope to resolve the scoped dependency.
builder.Services.AddSingleton<ICacheService>(sp =>
{
    using var scope = sp.CreateScope();
    return new CacheService(scope.ServiceProvider.GetRequiredService<IUserService>());
});

// FIX 2 — HttpClientFactory now defaults to SocketsHttpHandler in .NET 9;
// the (HttpClientHandler) cast would throw InvalidCastException at runtime.
// Use ConfigurePrimaryHttpMessageHandler (also fixes the CS0618 obsoletion).
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// FIX 3 — ForwardedHeaders middleware now rejects headers from unknown proxies.
// Register trusted proxy addresses so X-Forwarded-For is still processed.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));  // adjust to your proxy IP
});

// FIX 4 — HttpClientFactory Trace-level logs now redact ALL header values by default.
// Allowlist the specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Content-Type"
        && h != "Accept"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

